const getGamepadsInternal=()=>Array.from(navigator.getGamepads?.()??[]).filter((gamepad)=>gamepad!=null);
export const Toolbelt={Blazor:{Gamepad:{getGamepads(){return getGamepadsInternal().map((gamepad)=>[gamepad.id,gamepad.index.toString()]);},refresh(dotNetRef,id,index){const gamepad=getGamepadsInternal().find((candidate)=>candidate.id===id&&candidate.index===index);return dotNetRef.invokeMethodAsync("UpdateStatus",gamepad?.connected??false,gamepad?.axes??[],gamepad?.buttons?.map((button)=>button.pressed)??[],gamepad?.buttons?.map((button)=>button.value)??[]);}}}};
